var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"CITIZEN_NPC_PROSECUTOR_NULL","text":{"KOREA":"██양, 여기는 신성한 법정입니다.","JPN":"██さん、ここは神聖なる法廷です。","ENG":"Miss ██, you are under oath.","TWN":"██，這裡是神聖的法庭。"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CITIZEN_NPC_PROSECUTOR_NULL","text":{"KOREA":"거짓말 하지 말고 솔직하게 말하면 돼요.","JPN":"嘘をつかず、正直に答えてください。","ENG":"All you have to do is speak the truth.","TWN":"不可以說謊，只要照實說就好。"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_QM","text":{"KOREA":"……어른들이 그랬어요. 우리 엄마랑 아빠가 큰 잘못을 저질렀대요.","JPN":"……大人たちが言ってました。私のママとパパが大きな過ちを犯したって。","ENG":"...The adults told me. That my mom and dad did something very bad.","TWN":"……大人們說，我爸爸和媽媽犯下大錯。"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_QM","text":{"KOREA":"제가 솔직하게 말하면, 엄마랑 아빠는 감옥에 가나요?","JPN":"私が正直に話したら、ママとパパは刑務所に行くことになるんですか？","ENG":"If I tell the truth, will Mom and Dad go to prison?","TWN":"如果我說實話，那爸爸媽媽會進監獄嗎？"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CITIZEN_NPC_PROSECUTOR_NULL","text":{"KOREA":"그러지 않으려고 하는 거예요.","JPN":"そうならないように、今こうしているのです。","ENG":"We are doing this so that they don't.","TWN":"我現在就是想幫助他們。"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CITIZEN_NPC_PROSECUTOR_NULL","text":{"KOREA":"그 날 집에서 무슨 일이 있었는지 본 사람은 ██양뿐이에요.","JPN":"あの日、家で何があったのか。見たのは██さんだけです。","ENG":"You are the only witness of what happened at the house that day, Miss ██.","TWN":"那天在家裡發生的事，██是唯一的目擊者。"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CITIZEN_NPC_PROSECUTOR_NULL","text":{"KOREA":"██양의 증언이 중요합니다.","JPN":"██さんの証言が重要なのですよ。","ENG":"Your testimony is highly relevant to this case.","TWN":"██的證詞很重要。"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CITIZEN_NPC_PROSECUTOR_NULL","text":{"KOREA":"자, 그 날 ██양이 본 대로 재판장님께 설명해 주세요.","JPN":"では、あの日██さんが見たことを裁判長に説明してくれますか。","ENG":"Now, please describe to the judge what you saw that day.","TWN":"來，██，把你當天看到的，一五一十地跟法官說。"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_QM","text":{"KOREA":"……그 날 밤에, 아빠 친구라는 아저씨가 집에 찾아왔어요.","JPN":"……あの日の夜、パパの友だちだっていうおじさんが家に訪ねて来ました。","ENG":"...That night, a man who called himself a \\"friend\\" of my dad's visited us.","TWN":"……那天晚上，有一個叔叔來我們家，他說他是爸爸的朋友。"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_QM","text":{"KOREA":"엄마가 방에 들어가라고 해서 전 제 방에 있었어요.","JPN":"ママに部屋に行きなさいと言われたので、私は自分の部屋にいました。","ENG":"Mom told me to go to my room, so I stayed there.","TWN":"媽媽叫我進房間，所以我就待在自己的房間裡。"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_QM","text":{"KOREA":"그러다가…. 거실에서 엄마가 우는 소리가 들려서….","JPN":"それから……リビングでママが泣く声が聞こえて……","ENG":"Then... I heard my mom crying... and...","TWN":"突然間…從客廳傳來媽媽的哭聲…"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CITIZEN_NPC_PROSECUTOR_NULL","text":{"KOREA":"왜 울고 있었죠, ██양?","JPN":"どうして泣いていたのですか？　██さん。","ENG":"Why was she crying, Miss ██?","TWN":"██，媽媽為什麼哭呢？"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_QM","text":{"KOREA":"잘…. 잘 모르겠어요. 기억 안 나요.","JPN":"よく……よくわからないです。憶えてません。","ENG":"I... I'm not sure. I can't remember.","TWN":"我…我不知道，我不記得了。"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CITIZEN_NPC_PROSECUTOR_NULL","text":{"KOREA":"██양, 지금 증언을 바꾸면 곤란합니다.","JPN":"██さん、今証言を変えられては困ります。","ENG":"Miss ██, changing your testimony now is not a good idea.","TWN":"██，你現在改證詞會很麻煩。"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CITIZEN_NPC_PROSECUTOR_NULL","text":{"KOREA":"다시 한 번 묻죠. 왜 엄마가 울고 있었나요?","JPN":"もう一度聞きましょう。どうしてお母さんが泣いていたのですか？","ENG":"Let me ask again. Why was your mother crying?","TWN":"我再問你一次，媽媽為什麼在哭呢？"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_QM","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CITIZEN_NPC_PROSECUTOR_NULL","text":{"KOREA":"……하아.","JPN":"……はあ。","ENG":"...*Sigh*","TWN":"……呼。"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CITIZEN_NPC_PROSECUTOR_NULL","text":{"KOREA":"죄송합니다, 재판장님. 다음 증인을 신청하겠습니다.","JPN":"申し訳ありません、裁判長。次の証人を申請します。","ENG":"I'm sorry, your honor. I would like to call the next witness to the stand.","TWN":"抱歉，法官，我要聲請傳喚下一個證人。"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L22_1","type":"dialog","speaker":"CITIZEN_NPC_PROSECUTOR_NULL","text":{"KOREA":"이번 사건에 결정적인 제보를 해 주신 분이면서…….","JPN":"今度の事件で決定的な情報を提供した人であり……","ENG":"She provided crucial information to this case, and...","TWN":"她在此次案件中提供關鍵性的證詞……"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"narration","speaker":null,"text":{"KOREA":"꼴도 보기 싫은 사람이야.","JPN":"顔も見たくない。","ENG":"A disgusting human being.","TWN":"我不想看到她！"},"stage":{"bg":"CHARADE_001","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CITIZEN_NPC_RENT_NULL","text":{"KOREA":"더 이상은 못 참아!","JPN":"これ以上は我慢できない！","ENG":"That's enough!","TWN":"我真的是忍無可忍！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"CITIZEN_NPC_RENT_NULL","text":{"KOREA":"월세가 벌써 몇 달치 밀린 줄 알아? 넉 달치야!","JPN":"もう何カ月家賃を払ってないと思ってるんだ？　4か月だぞ！","ENG":"Do you have any idea how much you're behind on rent?! Four months!","TWN":"都已經欠幾個月的房租啦？整整四個月！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"에이, 아저씨. 누가 들으면 돈 떼어먹고 도망친 줄 알겠네.","JPN":"まあまあ、おっさん。人が聞いたらお金踏み倒して逃げたと勘違いするだろ？","ENG":"Oh, c'mon. You talk as if we robbed you or something, Mister.","TWN":"哎呀，大叔，別人聽到還以為我捲款潛逃呢。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"지금은 비수기라 그래. 돈 들어오면 갚는다니까.","JPN":"今はオフシーズンだから厳しくってさ。お金が入ってきたら払うって。","ENG":"It's off season now. We'll pay you when we get our money later.","TWN":"現在是淡季的嘛，只要有錢進來，我一定還你。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그러니까 삿대질 하지 말고, 어? 뭐 좋은 일이라고 변호사까지 끌고 와선.","JPN":"だから指さすのやめようよ。弁護士まで引き連れて、大ごとにしちゃって。","ENG":"So stop pointing that stubby finger at us, okay? Look at yourself, you even brought a lawyer into this.","TWN":"何苦這樣咄咄逼人？又不是什麼大事，幹嘛還找律師來呢？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CITIZEN_NPC_RENT_NULL","text":{"KOREA":"이봐요, 선생님. 매번 이런 식이라니까.","JPN":"ほらな、先生。毎度これだ。","ENG":"See, sir? They're always like this.","TWN":"律師，你看看，她每次都這樣。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CITIZEN_NPC_LAWER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CITIZEN_NPC_LAWER_NULL","text":{"KOREA":"네. 상담에서 들었던 대로군요.","JPN":"はい。相談で伺ったとおりですね。","ENG":"Yes. It's exactly as you described during our appointment.","TWN":"是，正如我在諮詢中所聽到的那樣。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CITIZEN_NPC_LAWER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CITIZEN_NPC_LAWER_NULL","text":{"KOREA":"두 분, 이미 불법 점거로 도시 관리국에 신고 들어갔어요.","JPN":"あなたたちのことはすでに不法占拠で都市管理局に通報済みです。","ENG":"You two have been reported to City Management for illegal occupation.","TWN":"二位，我們已經向城市管理局告發你們非法侵占。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CITIZEN_NPC_LAWER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CITIZEN_NPC_LAWER_NULL","text":{"KOREA":"시민증을 박탈당하기 싫으면 24시간 내로 이 집을 비워 주셔야 합니다.","JPN":"市民証を剥奪されたくなければ、24時間内にこの家から出ていってください。","ENG":"Please leave the property in 24 hours if you wish to maintain your citizen status.","TWN":"如果不希望被吊銷市民證，請在24小時內將房子清空。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CITIZEN_NPC_LAWER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아니, 시민증을 왜 박탈해? 등급이 떨어지면 떨어졌지.","JPN":"は？　なんで市民証を奪うんだ？　等級が落ちるだけだろ？","ENG":"What does that have to do with our status in the first place? Why not just demote our citizen grade?","TWN":"等等，為什麼要吊銷市民證？不是降級就好嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CITIZEN_NPC_LAWER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L43_1","type":"dialog","speaker":"CITIZEN_NPC_LAWER_NULL","text":{"KOREA":"물론 두 분이 성실한 준법 시민이시거나, 공탁금을 두둑하게 내셨다면 그랬겠죠.","JPN":"もちろんお二人が誠実な遵法市民であるか、供託金をたくさん払っていたならそうだったでしょうね。","ENG":"That would be the case if you were a law-abiding citizen or paid a large deposit.","TWN":"前提是你們必須是誠實守法的市民，或是有繳交足夠的押金。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CITIZEN_NPC_LAWER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L44_1","type":"dialog","speaker":"CITIZEN_NPC_LAWER_NULL","text":{"KOREA":"하지만 조회해 보니 두 분은 3등 시민이시더군요. 그것도 아주 아슬아슬하게.","JPN":"ですが、照会してみたところ、お二人は3等市民でした。それもギリギリの。","ENG":"However, it seems that both of you are grade 3 citizens. Barely.","TWN":"但根據查詢結果，二位是三等市民，而且還只是在及格邊緣而已。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CITIZEN_NPC_LAWER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L45_1","type":"dialog","speaker":"CITIZEN_NPC_LAWER_NULL","text":{"KOREA":"그 점수대에서는 뭐, 담배 꽁초만 버리다 걸려도 추방이죠.","JPN":"その点数帯では、まあ、タバコの吸殻を捨ててバレるだけでも追放です。","ENG":"At that point, something as minor as littering cigarette butts can get you deported.","TWN":"以你們的分數，只要亂丟菸蒂被抓到，就會立刻被驅逐出境。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CITIZEN_NPC_LAWER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L46_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아, 아하, 그러시구나아….","JPN":"あ、あは、そっか……","ENG":"Ah, aha, of course it can...","TWN":"喔～哈哈，是這樣喔…"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CITIZEN_NPC_LAWER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"……새끼 싸가지 겁나 없네, 진짜.","JPN":"……本当にウザイな、クソ野郎。","ENG":"...What a little piece of shit.","TWN":"……你這傢伙真是沒禮貌！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CITIZEN_NPC_LAWER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"CITIZEN_NPC_LAWER_NULL","text":{"KOREA":"방금 뭐라고 하셨죠? 여기 녹음기에 대고 다시 말씀해 주실래요?","JPN":"今なんて？　この録音機に向かって、もう一度話してもらえますか？","ENG":"What was that? Would you like to repeat that into this mic?","TWN":"你剛說什麼？請你對著錄音機再說一遍。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CITIZEN_NPC_LAWER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아, 아하하하! 꽁초는 안 버려 가지고! 비흡연자라서, 비흡연자!","JPN":"あ、あははは！　吸殻は捨てたことないな！　非喫煙者なんだ、非喫煙者！","ENG":"H-ha, ha ha! We would never litter! We don't even smoke! No smoking going on here!","TWN":"哈哈哈哈！我才不會亂丟煙蒂！我不會抽菸好嗎！給我搞清楚！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CITIZEN_NPC_LAWER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L1_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그래서 결국 우릴 내쫓겠다는 거죠?","JPN":"それで、結局私たちを追い出すってことですか？","ENG":"So, you're going to kick us out?","TWN":"所以意思是要把我們趕出去是吧？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"어디 마음대로 떠들어 봐요. 난 나갈 생각 없으니까.","JPN":"勝手に言っててください。私は出ていく気なんてないですから。","ENG":"Have at it. I'm not leaving.","TWN":"隨你們怎麼說，我是不會離開的。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CITIZEN_NPC_RENT_NULL","text":{"KOREA":"이거 봐, 이거이거. 내가 이 계집애 처음 봤을 때 눈깔부터 예사롭지 않았어.","JPN":"ほらな、これだよこれ。この小娘、初めて会った時からあの目つきが尋常じゃなかったんだよ。","ENG":"I knew it. I knew there was something wrong with this kid the moment I saw her.","TWN":"你聽聽看，你聽聽看。我第一次見到這個丫頭就覺得她不對勁。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CITIZEN_NPC_RENT_NULL","text":{"KOREA":"선생님, 됐고 어서 좀 쫓아내 주십시오.","JPN":"先生、いいから早く追い出してください。","ENG":"Sir, please just get them out of here.","TWN":"律師，少跟她們廢話，快把她們趕走！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CITIZEN_NPC_LAWER_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"CITIZEN_NPC_RENT_NULL","text":{"KOREA":"이것들, 태스크포스라더니 벌써 예전에 잘렸더라고.","JPN":"こいつら、タスクフォースって言ってたけど、とっくにクビになってたんだよ。","ENG":"They claimed to be TASKFORCE, but they were long fired.","TWN":"她們還說自己是特遣勢力，其實早就被炒魷魚了。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CITIZEN_NPC_LAWER_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CITIZEN_NPC_LAWER_NULL","text":{"KOREA":"그렇군요. 직장 여부를 속였다면 가중치가 더 심해질 텐데…….","JPN":"そうですね。在職の有無を偽っていたなら、罪が重くなる……","ENG":"Right. False occupation status is only going to make the offense more serious...","TWN":"是嗎？如果還隱瞞工作情況，那會加重刑責……"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CITIZEN_NPC_LAWER_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"앙!!","JPN":"あむ！！","ENG":"Nngh!!","TWN":"咬！！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"CITIZEN_NPC_LAWER_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_05"},{"id":"L13_1","type":"dialog","speaker":"CITIZEN_NPC_RENT_NULL","text":{"KOREA":"끄아아아악! 내 손가락! 이 애새끼가 내 손가락을 물어?!","JPN":"ぐわああああっ！　指が！　この小娘が、人の指を噛みやがって！","ENG":"AHHHH! My finger! This little brat just bit my finger!","TWN":"哎呀呀呀！我的手！這傢伙竟然咬我的手？！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"CITIZEN_NPC_LAWER_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아, 그러길래 삿대질 좀 하지 말라니까!","JPN":"あーあ、だから指さすなって言ったのに！","ENG":"Ugh, I told you not to point your finger at us!","TWN":"哎呀！我就怕會這樣，才叫你不要咄咄逼人的嘛！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"야! 사이코 꼬맹이! 그딴 거 씹지 마! 개껌 줄게, 개껌!","JPN":"おい！　サイコガキ！　あんなの噛むな！　犬用ガムあげるから、ガム！","ENG":"Hey! You psycho kid, stop biting that! I'll give you a dog bone!","TWN":"喂！小瘋子！不要咬那個！我拿潔牙骨給你！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CITIZEN_NPC_RENT_NULL","text":{"KOREA":"아아악! 내 손가락이 개껌이냐, 이 빌어먹을 년아!","JPN":"あああ！　俺の指を噛むな、このクソガキ！","ENG":"Ahhh! My finger's not a dog bone, you brat!","TWN":"啊啊啊！我的手指頭是潔牙骨嗎！該死的臭丫頭！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"앙 애아 아이아오어! 애어 아으 어 이어어어!! (난 개가 아니라구요! 개껌 같은 거 필요없어!!)","JPN":"ああいあいうやあいえう！　いうようあうあんあいああい！！(私は犬じゃないです！　犬用ガムなんかいらない！！)","ENG":"In na a ohg! I on eed og ohnes!! (I'm not a dog! I don't need dog bones!!)","TWN":"汪汪汪汪汪！汪汪汪汪汪！！(我才不是狗！才不要潔牙骨！)"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"알겠으니까 떨어지라고 좀!","JPN":"わかったから離れろよ！","ENG":"Fine, just let go!","TWN":"好啦，你先鬆口！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"너도 구경하지 말고 좀 도와! 의뢰인 손가락 날아가는 꼴 보고 싶냐!?","JPN":"あんたも見てないでちょっとは手伝えよ！　依頼人の指がなくなる様を見たいのか！？","ENG":"Do something! You wanna see your client lose a finger?!","TWN":"你在旁邊看戲嗎？還不快來幫忙！是想看到委託人的斷指秀嗎！？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CITIZEN_NPC_LAWER_NULL","text":{"KOREA":"아, 아아, 네! 알겠습니다!","JPN":"あ、ああ、はい！　わかりました！","ENG":"Ah, uh, right! Okay!","TWN":"喔喔喔，是！我也來幫忙！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CITIZEN_NPC_LAWER_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"CITIZEN_NPC_RENT_NULL","text":{"KOREA":"허억……. 허억…….","JPN":"はあ……はあ……","ENG":"*Huff* *Huff*","TWN":"嗚嗚……嗚嗚……"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CITIZEN_NPC_LAWER_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"CITIZEN_NPC_LAWER_NULL","text":{"KOREA":"상해죄도 추가하겠군요. 당신들은 이 도시에 있어선 안 될 자들이에요.","JPN":"傷害罪も追加ですね。あなたたちはこの街にいてはいけない人たちです。","ENG":"That'll be additional assault charges for you. You don't belong in this city.","TWN":"看來還要再加一條傷害罪，你們根本就不該存在於這座城市裡！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CITIZEN_NPC_LAWER_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아니, 그러지 말고! 같이 싸운 전우끼리 야박하게 그러기야?","JPN":"いや、そう言わず！　一緒に戦った戦友のくせに冷たいな。","ENG":"Oh, c'mon! How can you do that to a fellow comrade?!","TWN":"唉唷，先別衝動！我們不是一起並肩作戰的好戰友嗎？不要這麼無情嘛？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CITIZEN_NPC_LAWER_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"CITIZEN_NPC_LAWER_NULL","text":{"KOREA":"전우라니요?","JPN":"戦友？","ENG":"Comrade?","TWN":"什麼戰友？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CITIZEN_NPC_LAWER_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"댁이랑 나랑 저 사이코 꼬맹이 떼어내느라 격전을 벌였잖아.","JPN":"お宅と私は、あのサイコガキを外すために激戦を共にした仲じゃないか。","ENG":"We fought together to get that kid off of your client.","TWN":"你剛才不是和我一起經歷一場激戰，把小瘋子拉開嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CITIZEN_NPC_LAWER_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"이거 얼른 풀어요! 안 풀어요!?","JPN":"早くこれ解きなさいよ！　ちょっと！？","ENG":"Let me go! You can't do this to me!","TWN":"放開我啦！還不快把繩子鬆開！？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"라이카, 이 배신자!! 돈만 아는 암캐! 승냥이! 잡종견! 똥강아지!","JPN":"ライカ、この裏切り者！！　お金ばかりのクソ犬！　山犬！　雑種！　バカ犬！","ENG":"Laika, you traitor!! Money-hungry mongrel!! Mutt!! Cur!!","TWN":"萊卡，你這個叛徒！！眼裡只有錢的母狗！豺犬！米克斯！土狗！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CITIZEN_NPC_LAWER_NULL","text":{"KOREA":"……확실히 격전이었죠. 네.","JPN":"……確かに激戦でしたね。はい。","ENG":"...Well, I can't deny it was a tough battle.","TWN":"……確實是場激戰沒錯。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CITIZEN_NPC_LAWER_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그래. 나라고 뭐 쟤 뒤치다꺼리 좋아서 여기 있는 줄 알아?","JPN":"そうだろ。私も好き好んであいつのお世話してるわけじゃないんだよ。","ENG":"Yeah. What, you think I'm here because I like babysitting her?","TWN":"是啊，你以為我是喜歡替她擦屁股，才待在這裡的嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CITIZEN_NPC_LAWER_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"이렇게 된 데에는 다 피치 못할 사정이 있다니까.","JPN":"こうなったのには、やむを得ない事情ってもんがあるんだ。","ENG":"It's not like I had a choice.","TWN":"我都是有苦衷的。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CITIZEN_NPC_LAWER_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"CITIZEN_NPC_LAWER_NULL","text":{"KOREA":"피치 못할 사정이라뇨?","JPN":"やむを得ない事情というと？","ENG":"What do you mean?","TWN":"什麼苦衷？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CITIZEN_NPC_LAWER_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"하아, 그게 말이지…….","JPN":"はあ、それがね……","ENG":"*Sigh* The thing is...","TWN":"哀，聽我娓娓道來……"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CITIZEN_NPC_LAWER_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"혹시 그 날 기억해?","JPN":"もしかして、あの日のこと覚えてる？","ENG":"Do you remember that day?","TWN":"還記得那天嗎？"},"stage":{"bg":"HORIZON_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"브리트라가 떼거지로 나타났다가 사라졌다던 날.","JPN":"ブリトラが群れで現れて消えたって日。","ENG":"When a swarm of Britra appeared and disappeared.","TWN":"就是佈雷特成群出現後又消失的那天。"},"stage":{"bg":"HORIZON_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};